from dataclasses import dataclass, field
from datetime import date, timedelta
from enum import Enum

class NYDFSReportType(str, Enum):
    ANNUAL_ATTESTATION = "annual_attestation"     # Due Feb 15 each year
    MATERIAL_CYBER     = "material_cyber_event"   # 72-hour notice
    RANSOMWARE         = "extortion_payment"      # 24-hour notice

@dataclass
class NYDFSFiling:
    report_type: NYDFSReportType
    due_date: date
    submitted_date: date | None = None
    content_summary: str = ""

    @property
    def is_overdue(self) -> bool:
        if self.submitted_date:
            return False
        return date.today() > self.due_date

    @property
    def days_remaining(self) -> int:
        return (self.due_date - date.today()).days

def annual_attestation_due(year: int) -> date:
    """NYDFS Part 500 annual certification: due February 15.""""
    return date(year, 2, 15)

def material_cyber_due(discovery_date: date) -> date:
    """NYDFS: notify within 72 hours of determining event is material.""""
    return discovery_date + timedelta(hours=72)

# AI-related triggers for NYDFS material cyber event reporting:
AI_MATERIAL_TRIGGERS = [
    "Unauthorised access to AI training data containing customer records",
    "LLM API key compromise leading to unauthorised inference",
    "Adversarial attack causing AI-driven fraud detection outage > 4 hours",
    "Model exfiltration from production model registry",
    "Prompt injection causing disclosure of customer PII in AI output",
]

from dataclasses import dataclass
from enum import Enum

class MaterialityFactor(str, Enum):
    FINANCIAL_IMPACT    = "financial_impact"
    CUSTOMER_HARM       = "customer_harm"
    REGULATORY_EXPOSURE = "regulatory_exposure"
    REPUTATIONAL_IMPACT = "reputational_impact"
    OPERATIONAL_IMPACT  = "operational_impact"

@dataclass
class AIEventMaterialityAssessment:
    event_description: str
    # Score each factor 0 (none) to 3 (severe)
    financial_impact: int       # Revenue loss, remediation cost, fines
    customer_harm: int          # Number affected, severity of harm
    regulatory_exposure: int    # Known regulatory violation, enforcement risk
    reputational_impact: int    # Media coverage, brand damage
    operational_impact: int     # System downtime, process disruption

    @property
    def total_score(self) -> int:
        return (
            self.financial_impact + self.customer_harm +
            self.regulatory_exposure + self.reputational_impact +
            self.operational_impact
        )

    @property
    def is_material(self) -> bool:
        """
        SEC defines materiality as information a reasonable investor would
        consider important. Score ≥ 7 is a conservative proxy for materiality
        review escalation; legal counsel makes the final determination.
        """
        return self.total_score >= 7 or self.regulatory_exposure >= 3

    def required_disclosures(self) -> list[str]:
        disclosures = []
        if self.is_material:
            disclosures.append("SEC 8-K (Item 1.05) within 4 business days of materiality determination")
        if self.regulatory_exposure >= 2:
            disclosures.append("NYDFS notification within 72 hours if cybersecurity related")
        if self.customer_harm >= 2:
            disclosures.append("State breach notification laws (timing varies by state)")
        if self.is_material:
            disclosures.append("Board/Audit Committee briefing before public filing")
        return disclosures
